#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        cnt0 = s.count('0')
        cnt1 = N - cnt0
        if cnt0 == 0 or cnt1 == 0:
            out.append('Bob')
        elif cnt0 % 2 == 1 or cnt1 % 2 == 1:
            out.append('Alice')
        else:
            out.append('Bob')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

